insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('c63ed9f0-004c-5e5a-97b1-78e51193b0e4','6a0ae2e5-071f-56b2-a3c5-05b19f0e6a7e',1,$p$Futuro do pretérito: cortesía, deseo e hipótesis$p$,$p$Futuro do pretérito: cortesía, deseo e hipótesis$p$,'lesson',15),
 ('4f6b170d-473f-562c-9349-579c903893b2','6a0ae2e5-071f-56b2-a3c5-05b19f0e6a7e',2,$p$Hipótesis real: se + futuro do subjuntivo → presente/futuro$p$,$p$Hipótesis real: se + futuro do subjuntivo → presente/futuro$p$,'lesson',15),
 ('05fb28da-7292-50f8-ba48-e0ac465febb7','6a0ae2e5-071f-56b2-a3c5-05b19f0e6a7e',3,$p$Irreal del presente: se + imperfeito do subjuntivo → …ria$p$,$p$Irreal del presente: se + imperfeito do subjuntivo → …ria$p$,'lesson',15),
 ('3cb0a9d6-aadd-5c91-8a37-286d546edddf','6a0ae2e5-071f-56b2-a3c5-05b19f0e6a7e',4,$p$Irreal del pasado: se tivesse + particípio → teria + particípio$p$,$p$Irreal del pasado: se tivesse + particípio → teria + particípio$p$,'lesson',15),
 ('b696e425-0c7f-5409-8bb3-9d78135c38a5','6a0ae2e5-071f-56b2-a3c5-05b19f0e6a7e',5,$p$🏁 Checkpoint Unidade 21$p$,$p$Usa el futuro do pretérito simple (-ria: falaria, faria) para cortesía, deseo e hipótesis, forma el futuro do pretérito compuesto (teria/seria + particípio) y arma los tres tipos de período hipotético con «se»: real (se + futuro do subjuntivo → presente/futuro), irreal del presente (se + imperfeito do subjuntivo → futuro do pretérito) e irreal del pasado (se + mais-que-perfeito do subjuntivo → futuro do pretérito composto).$p$,'checkpoint',40)
