('baee1a11-2467-52f2-86a0-a1d1f8655630'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','reading','match',$p$Une cada frase cortés en futuro do pretérito con su significado.$p$,$j${"pairs": [{"en": "Você poderia repetir, por favor?", "es": "¿Podrías repetir, por favor?"}, {"en": "Eu gostaria de reservar uma mesa.", "es": "Me gustaría reservar una mesa."}, {"en": "Nós adoraríamos conhecer o Rio.", "es": "Nos encantaría conocer Río."}]}$j$::jsonb,$j${"pairs": [["Você poderia repetir, por favor?", "¿Podrías repetir, por favor?"], ["Eu gostaria de reservar uma mesa.", "Me gustaría reservar una mesa."], ["Nós adoraríamos conhecer o Rio.", "Nos encantaría conocer Río."]]}$j$::jsonb,0.68,ARRAY[$p$unidad21$p$, $p$futuro_preterito_cortesia$p$, $p$reading$p$]),
('110afe60-a508-56a7-9c3a-ffd3f632c951'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','reading','multiple_choice',$p$«En tu lugar, yo no diría nada.» ¿Cuál usa bien el futuro do pretérito irregular del verbo «dizer»?$p$,$j${"options": ["No seu lugar, eu não diria nada.", "No seu lugar, eu não dizeria nada.", "No seu lugar, eu não direi nada."]}$j$::jsonb,$j${"value": "No seu lugar, eu não diria nada."}$j$::jsonb,0.68,ARRAY[$p$unidad21$p$, $p$futuro_preterito_irregular$p$, $p$reading$p$]),
