('25a5a102-ed36-531c-807c-7c0fd8b4316f'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','reading','match',$p$Une cada frase de condición real (futuro do subjuntivo) con su significado.$p$,$j${"pairs": [{"en": "Quando eu puder, eu resolvo isso.", "es": "Cuando pueda, resuelvo eso."}, {"en": "Se você quiser, a gente sai hoje.", "es": "Si quieres, salimos hoy."}, {"en": "Assim que ele chegar, avise.", "es": "En cuanto él llegue, avisa."}]}$j$::jsonb,$j${"pairs": [["Quando eu puder, eu resolvo isso.", "Cuando pueda, resuelvo eso."], ["Se você quiser, a gente sai hoje.", "Si quieres, salimos hoy."], ["Assim que ele chegar, avise.", "En cuanto él llegue, avisa."]]}$j$::jsonb,0.68,ARRAY[$p$unidad21$p$, $p$hipotetico_real_quando$p$, $p$reading$p$]),
('20b5792b-78eb-500c-a6df-530430462c2f'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','reading','multiple_choice',$p$Hipótesis irreal del presente: «Si yo tuviera dinero, viajaría por el mundo.» ¿Cuál combina bien imperfeito do subjuntivo y futuro do pretérito?$p$,$j${"options": ["Se eu tivesse dinheiro, eu viajaria pelo mundo.", "Se eu tinha dinheiro, eu viajaria pelo mundo.", "Se eu tiver dinheiro, eu viajaria pelo mundo."]}$j$::jsonb,$j${"value": "Se eu tivesse dinheiro, eu viajaria pelo mundo."}$j$::jsonb,0.68,ARRAY[$p$unidad21$p$, $p$irreal_presente_choice$p$, $p$reading$p$]),
('ee48055b-9e1e-5267-8763-cd600888a5af'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','reading','multiple_choice',$p$Hipótesis irreal del pasado: «Si yo hubiera estudiado, habría aprobado.» ¿Cuál usa mais-que-perfeito do subjuntivo y futuro do pretérito compuesto?$p$,$j${"options": ["Se eu tivesse estudado, eu teria passado.", "Se eu tivesse estudado, eu tinha passado.", "Se eu tivera estudado, eu teria passado."]}$j$::jsonb,$j${"value": "Se eu tivesse estudado, eu teria passado."}$j$::jsonb,0.68,ARRAY[$p$unidad21$p$, $p$irreal_passado_choice$p$, $p$reading$p$]),
('1c9ea552-4445-56e5-b169-4c4fac1ceed5'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','writing','cloze',$p$Completa con el futuro do pretérito del verbo «gostar» (deseo cortés, 1ª persona): «Eu ___ de morar perto do mar.» (me gustaría)$p$,$j${"text": "Eu ___ de morar perto do mar."}$j$::jsonb,$j${"value": "gostaria", "accepted": ["gostaria", "Gostaria"]}$j$::jsonb,0.68,ARRAY[$p$unidad21$p$, $p$futuro_preterito_desejo_cloze$p$, $p$writing$p$]),
('85c52cf1-8102-5777-b32c-5347f79469f3'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','writing','translation',$p$Traduce usando el futuro do pretérito (haría): «En tu lugar, yo haría lo mismo.»$p$,$j${"source": "En tu lugar, yo haría lo mismo."}$j$::jsonb,$j${"value": "No seu lugar, eu faria a mesma coisa.", "accepted": ["No seu lugar, eu faria a mesma coisa.", "No seu lugar, eu faria a mesma coisa", "No seu lugar, eu faria o mesmo.", "No seu lugar, eu faria o mesmo", "No teu lugar, eu faria a mesma coisa."]}$j$::jsonb,0.68,ARRAY[$p$unidad21$p$, $p$futuro_preterito_hipotese_translation$p$, $p$writing$p$]),
('cb49f684-bd08-5ee4-9e22-e5b60df001e6'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','writing','cloze',$p$Completa con el futuro do subjuntivo del verbo «poder» en negativo (condición real, si no puedes/pudieres). Dos palabras: «Se você ___ vir, me avise antes.»$p$,$j${"text": "Se você ___ vir, me avise antes."}$j$::jsonb,$j${"value": "não puder", "accepted": ["não puder", "Não puder", "nao puder", "não puder."]}$j$::jsonb,0.68,ARRAY[$p$unidad21$p$, $p$hipotetico_real_cloze$p$, $p$writing$p$]),
('b091a13e-7d19-52dc-9ce8-313e440f6a41'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','writing','word_bank',$p$Ordena para formar: «Si yo tuviera más tiempo, aprendería a tocar guitarra.» (Se eu tivesse mais tempo, aprenderia a tocar violão.)$p$,$j${"tiles": ["Se", "eu", "tivesse", "mais", "tempo", "aprenderia", "a", "tocar", "violão", "aprendia", "tiver"]}$j$::jsonb,$j${"value": "Se eu tivesse mais tempo aprenderia a tocar violão", "sequence": ["Se", "eu", "tivesse", "mais", "tempo", "aprenderia", "a", "tocar", "violão"]}$j$::jsonb,0.68,ARRAY[$p$unidad21$p$, $p$irreal_presente_wordbank$p$, $p$writing$p$]),
('c5080e37-fcb5-5cc1-aeaf-c2ff2c8a7cb9'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','writing','translation',$p$Traduce la hipótesis irreal del presente: «Si él estuviera aquí, nos ayudaría.»$p$,$j${"source": "Si él estuviera aquí, nos ayudaría."}$j$::jsonb,$j${"value": "Se ele estivesse aqui, ele nos ajudaria.", "accepted": ["Se ele estivesse aqui, ele nos ajudaria.", "Se ele estivesse aqui, ele nos ajudaria", "Se ele estivesse aqui, nos ajudaria.", "Se ele estivesse aqui, ele nos ajudaria."]}$j$::jsonb,0.68,ARRAY[$p$unidad21$p$, $p$irreal_presente_translation$p$, $p$writing$p$]),
('a652f6bd-afc8-5289-9db3-1ee624b74938'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','writing','cloze',$p$Completa con el auxiliar en mais-que-perfeito do subjuntivo (dos palabras: tivesse + participio de «estudar»): «Se eu ___ para a prova, teria ido melhor.» (hubiera estudiado)$p$,$j${"text": "Se eu ___ para a prova, teria ido melhor."}$j$::jsonb,$j${"value": "tivesse estudado", "accepted": ["tivesse estudado", "Tivesse estudado"]}$j$::jsonb,0.68,ARRAY[$p$unidad21$p$, $p$irreal_passado_auxiliar_cloze$p$, $p$writing$p$]),
