('6efdef23-6c5a-5145-b7a8-3e2267a9363f'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','reading','match',$p$Une cada frase en voz pasiva con su significado.$p$,$j${"pairs": [{"en": "A carta foi escrita por Maria.", "es": "La carta fue escrita por María."}, {"en": "Os livros foram vendidos ontem.", "es": "Los libros fueron vendidos ayer."}, {"en": "As casas serão construídas aqui.", "es": "Las casas serán construidas aquí."}, {"en": "O relatório é revisado todo mês.", "es": "El informe es revisado cada mes."}]}$j$::jsonb,$j${"pairs": [["A carta foi escrita por Maria.", "La carta fue escrita por María."], ["Os livros foram vendidos ontem.", "Los libros fueron vendidos ayer."], ["As casas serão construídas aqui.", "Las casas serán construidas aquí."], ["O relatório é revisado todo mês.", "El informe es revisado cada mes."]]}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$voz_passiva_analitica$p$, $p$reading$p$]),
