('9ecc94e7-c0a1-5901-ba1b-e60f43739e77'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','writing','cloze',$p$Anuncio: 'se alquila un apartamento'. Pasiva pronominal: verbo 'alugar' en singular + '-se' pospuesto con guion.$p$,$j${"text": "___ apartamento mobiliado no centro da cidade."}$j$::jsonb,$j${"value": "Aluga-se", "accepted": ["Aluga-se", "aluga-se"]}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$passiva_sintetica_se$p$, $p$writing$p$]),
('c00cb7d2-6e60-579d-899e-e54767ed9c67'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','reading','match',$p$Une cada frase con su significado. Fíjate en 'ser' (acción) vs 'estar' (estado/resultado).$p$,$j${"pairs": [{"en": "A porta foi fechada pelo porteiro.", "es": "La puerta fue cerrada por el portero (acción)."}, {"en": "A porta está fechada agora.", "es": "La puerta está cerrada ahora (estado)."}, {"en": "O trabalho já está feito.", "es": "El trabajo ya está hecho (resultado)."}]}$j$::jsonb,$j${"pairs": [["A porta foi fechada pelo porteiro.", "La puerta fue cerrada por el portero (acción)."], ["A porta está fechada agora.", "La puerta está cerrada ahora (estado)."], ["O trabalho já está feito.", "El trabajo ya está hecho (resultado)."]]}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$estar_vs_ser_participio$p$, $p$reading$p$]),
('408d7f37-742b-54ff-a27e-6fa5c55910da'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','writing','translation',$p$Traduce a português (estado/resultado con 'estar', no acción): 'El trabajo ya está hecho.'$p$,$j${"source": "El trabajo ya está hecho."}$j$::jsonb,$j${"value": "O trabalho já está feito.", "accepted": ["O trabalho já está feito.", "O trabalho já está feito", "o trabalho já está feito", "O trabalho está feito", "o trabalho está feito"]}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$estar_vs_ser_participio$p$, $p$writing$p$]),
('e99e58c8-561f-5f9c-968e-708244502976'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','listening','listening',$p$Escucha y elige la frase que oíste.$p$,$j${"options": ["A janela está quebrada desde a tempestade.", "A janela foi limpa antes da reunião.", "A janela será trocada na próxima semana."], "say": "A janela está quebrada desde a tempestade.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/e99e58c8-561f-5f9c-968e-708244502976.mp3"}$j$::jsonb,$j${"value": "A janela está quebrada desde a tempestade."}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$estar_vs_ser_participio$p$, $p$listening$p$]),
('11eab62a-b69b-5344-85f1-8471efab8477'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','reading','multiple_choice',$p$Con 'ser/estar' se usa el participio irregular; con 'ter' el regular. Elige la frase correcta.$p$,$j${"options": ["A encomenda foi entregue hoje de manhã.", "A encomenda tem entregado toda semana.", "A encomenda está entregado hoje de manhã."]}$j$::jsonb,$j${"value": "A encomenda foi entregue hoje de manhã."}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$participios_duplos$p$, $p$reading$p$]),
('7b4a8595-be8e-5764-973a-f112572778db'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','writing','cloze',$p$Con 'ter' se usa el participio regular (terminado en -ado). Pluscuamperfecto del verbo 'aceitar'.$p$,$j${"text": "Eu já tinha ___ a proposta antes da reunião começar."}$j$::jsonb,$j${"value": "aceitado", "accepted": ["aceitado", "Aceitado"]}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$participios_duplos$p$, $p$writing$p$]),
('0b929ee8-3f19-5662-9ebf-5bf774f5d806'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','reading','match',$p$Une cada frase con su significado. Observa el participio irregular con 'ser/estar'.$p$,$j${"pairs": [{"en": "A conta já foi paga.", "es": "La cuenta ya fue pagada."}, {"en": "O prêmio foi ganho pela equipe.", "es": "El premio fue ganado por el equipo."}, {"en": "Os documentos foram impressos.", "es": "Los documentos fueron impresos."}]}$j$::jsonb,$j${"pairs": [["A conta já foi paga.", "La cuenta ya fue pagada."], ["O prêmio foi ganho pela equipe.", "El premio fue ganado por el equipo."], ["Os documentos foram impressos.", "Los documentos fueron impresos."]]}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$participios_duplos$p$, $p$reading$p$]),
('9e40942a-e643-5581-9040-5560f6724efa'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','listening','listening',$p$Escucha y elige la frase que oíste.$p$,$j${"options": ["O prêmio foi ganho pela equipe brasileira.", "O contrato foi assinado pelo gerente responsável.", "A fatura já está paga desde a semana passada."], "say": "O prêmio foi ganho pela equipe brasileira.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/9e40942a-e643-5581-9040-5560f6724efa.mp3"}$j$::jsonb,$j${"value": "O prêmio foi ganho pela equipe brasileira."}$j$::jsonb,0.68,ARRAY[$p$unidad22$p$, $p$participios_duplos$p$, $p$listening$p$]),
