('f84ba8df-1b88-59a4-8c12-92d35f15b215'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','reading','multiple_choice',$p$Convierte la pregunta directa «Você tem tempo?» en indirecta reportada en pasado. Elige la opción correcta.$p$,$j${"options": ["Ele perguntou se eu tinha tempo.", "Ele perguntou que eu tinha tempo.", "Ele perguntou tenho tempo."]}$j$::jsonb,$j${"value": "Ele perguntou se eu tinha tempo."}$j$::jsonb,0.68,ARRAY[$p$unidad23$p$, $p$pergunta_indireta_se$p$, $p$reading$p$]),
