 ('06104a13-1373-504b-9618-cba91352170b','f665244d-83db-5ba0-bd57-c1a3ed1bd801',1,$p$Concesivas y condicionales + subjuntivo (embora, caso, contanto que)$p$,$p$Concesivas y condicionales + subjuntivo (embora, caso, contanto que)$p$,'lesson',15),
 ('7c6663bb-23d3-5933-9527-db157779c8df','f665244d-83db-5ba0-bd57-c1a3ed1bd801',2,$p$Conjunciones + indicativo (à medida que, ao passo que, porque)$p$,$p$Conjunciones + indicativo (à medida que, ao passo que, porque)$p$,'lesson',15),
 ('8573a349-f83a-5811-8146-66168a4d27c8','f665244d-83db-5ba0-bd57-c1a3ed1bd801',3,$p$Conectores textuales (contudo, no entanto, portanto, além disso)$p$,$p$Conectores textuales (contudo, no entanto, portanto, além disso)$p$,'lesson',15),
 ('c1912523-4a15-5985-b791-7d9d2671e14e','f665244d-83db-5ba0-bd57-c1a3ed1bd801',4,$p$Regencia verbal (assistir a, obedecer a, gostar de, precisar de)$p$,$p$Regencia verbal (assistir a, obedecer a, gostar de, precisar de)$p$,'lesson',15),
 ('d53f17d1-5831-5ac4-963a-bce2e142c514','f665244d-83db-5ba0-bd57-c1a3ed1bd801',5,$p$🏁 Checkpoint Unidade 24$p$,$p$Demuestra que dominas las conjunciones subordinantes con SUBJUNTIVO (concesivas embora/ainda que, condicionales caso/contanto que/a menos que, finales para que, temporales antes que/até que), las que exigen INDICATIVO (à medida que, ao passo que, porque, já que), los conectores textuales B2 (contudo, no entanto, portanto, além disso, ou seja) y la regencia verbal correcta (assistir A, obedecer A, gostar DE, precisar DE).$p$,'checkpoint',40)
