('09c84263-2b92-5356-9702-ee407e22ac90'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','reading','match',$p$Une cada oración en portugués con su traducción.$p$,$j${"pairs": [{"en": "Embora chova, vou sair.", "es": "Aunque llueva, voy a salir."}, {"en": "Caso precise, me avise.", "es": "En caso de que necesites, avísame."}, {"en": "Vou, contanto que você venha.", "es": "Voy, con tal de que vengas."}, {"en": "Não saio a menos que pare.", "es": "No salgo a menos que pare."}]}$j$::jsonb,$j${"pairs": [["Embora chova, vou sair.", "Aunque llueva, voy a salir."], ["Caso precise, me avise.", "En caso de que necesites, avísame."], ["Vou, contanto que você venha.", "Voy, con tal de que vengas."], ["Não saio a menos que pare.", "No salgo a menos que pare."]]}$j$::jsonb,0.68,ARRAY[$p$unidad24$p$, $p$concessivas_condicionais_match$p$, $p$reading$p$]),
('49961c9c-cb00-5196-bc92-27b519cf9c56'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','reading','multiple_choice',$p$'embora' exige presente de subjuntivo. Completa: 'Aunque él esté cansado, va a trabajar.'$p$,$j${"options": ["Embora ele esteja cansado, vai trabalhar.", "Embora ele está cansado, vai trabalhar.", "Embora ele estava cansado, vai trabalhar."]}$j$::jsonb,$j${"value": "Embora ele esteja cansado, vai trabalhar."}$j$::jsonb,0.68,ARRAY[$p$unidad24$p$, $p$embora_subjuntivo$p$, $p$reading$p$]),
('65b7e6f9-c81a-566c-8e79-7820f5484acc'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','writing','cloze',$p$'caso' exige presente de subjuntivo (no indicativo). Conjuga el verbo 'precisar' en la forma correcta: 'En caso de que necesites ayuda, llámame.'$p$,$j${"text": "Caso você ___ de ajuda, me ligue."}$j$::jsonb,$j${"value": "precise", "accepted": ["precise", "Precise"]}$j$::jsonb,0.68,ARRAY[$p$unidad24$p$, $p$caso_subjuntivo_cloze$p$, $p$writing$p$]),
('89ccf3bf-c7b8-574e-826b-b84b77fb0db2'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','listening','listening',$p$Escucha y elige la frase que oíste.$p$,$j${"options": ["Ainda que seja difícil, nós vamos tentar.", "Ainda que era difícil, nós vamos tentar.", "Já que é difícil, nós vamos desistir."], "say": "Ainda que seja difícil, nós vamos tentar.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/89ccf3bf-c7b8-574e-826b-b84b77fb0db2.mp3"}$j$::jsonb,$j${"value": "Ainda que seja difícil, nós vamos tentar."}$j$::jsonb,0.68,ARRAY[$p$unidad24$p$, $p$ainda_que_listen$p$, $p$listening$p$]),
('b7e9609a-4ae9-5fc5-811f-fed25f4d531a'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','reading','match',$p$Une cada conjunción con su valor y traducción.$p$,$j${"pairs": [{"en": "à medida que", "es": "a medida que (proporción)"}, {"en": "ao passo que", "es": "mientras que (contraste)"}, {"en": "já que", "es": "ya que (causa)"}, {"en": "assim que", "es": "en cuanto (tiempo)"}]}$j$::jsonb,$j${"pairs": [["à medida que", "a medida que (proporción)"], ["ao passo que", "mientras que (contraste)"], ["já que", "ya que (causa)"], ["assim que", "en cuanto (tiempo)"]]}$j$::jsonb,0.68,ARRAY[$p$unidad24$p$, $p$indicativo_match$p$, $p$reading$p$]),
('9b6b0d10-336f-511f-8a2a-eff92d91edcf'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','reading','multiple_choice',$p$'à medida que' exige INDICATIVO (no subjuntivo). Completa: 'A medida que el tiempo pasa, aprendo más.'$p$,$j${"options": ["À medida que o tempo passa, aprendo mais.", "À medida que o tempo passasse, aprendia mais.", "À medida que o tempo tenha passado, aprendo mais."]}$j$::jsonb,$j${"value": "À medida que o tempo passa, aprendo mais."}$j$::jsonb,0.68,ARRAY[$p$unidad24$p$, $p$a_medida_que_indicativo$p$, $p$reading$p$]),
('e69294b3-a7c1-5995-90af-9bde26c46dac'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','writing','cloze',$p$'ao passo que' marca contraste + INDICATIVO. Escribe el conector de tres palabras (empieza por 'ao'): 'Yo estudio, mientras que él descansa.'$p$,$j${"text": "Eu estudo, ___ ele descansa."}$j$::jsonb,$j${"value": "ao passo que", "accepted": ["ao passo que", "Ao passo que"]}$j$::jsonb,0.68,ARRAY[$p$unidad24$p$, $p$ao_passo_que_cloze$p$, $p$writing$p$]),
('87dfff8c-030f-5b92-aeef-24ff20392224'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','writing','translation',$p$Traduce al portugués usando 'porque' + indicativo (no subjuntivo).$p$,$j${"source": "No fui a la fiesta porque estaba muy cansado."}$j$::jsonb,$j${"value": "Eu não fui à festa porque estava muito cansado.", "accepted": ["Eu não fui à festa porque estava muito cansado", "Eu não fui à festa porque estava muito cansado.", "Não fui à festa porque estava muito cansado.", "Não fui à festa porque estava muito cansado", "Eu não fui à festa porque eu estava muito cansado.", "Eu não fui à festa porque eu estava muito cansado"]}$j$::jsonb,0.68,ARRAY[$p$unidad24$p$, $p$porque_indicativo_translation$p$, $p$writing$p$]),
('8c903194-ecfe-594b-be6e-282e132a2db8'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','listening','listening',$p$Escucha y elige la frase que oíste.$p$,$j${"options": ["Já que você chegou, vamos começar a reunião.", "Já que você chegasse, vamos começar a reunião.", "Visto que você saiu, vamos terminar a reunião."], "say": "Já que você chegou, vamos começar a reunião.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/8c903194-ecfe-594b-be6e-282e132a2db8.mp3"}$j$::jsonb,$j${"value": "Já que você chegou, vamos começar a reunião."}$j$::jsonb,0.68,ARRAY[$p$unidad24$p$, $p$ja_que_listen$p$, $p$listening$p$]),
('ff5048c2-2e48-54c9-b1af-50811157fe27'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','reading','multiple_choice',$p$Elige el conector adecuado. La segunda idea CONTRADICE la primera: 'Estudió mucho; ___, no aprobó.'$p$,$j${"options": ["no entanto", "além disso", "portanto"]}$j$::jsonb,$j${"value": "no entanto"}$j$::jsonb,0.68,ARRAY[$p$unidad24$p$, $p$conectores_textuais_reading$p$, $p$reading$p$]),
('73694996-b2b1-5199-9afc-cafd7ee02066'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','writing','cloze',$p$Falta el conector conclusivo (sinónimo de 'por lo tanto', una sola palabra que empieza por 'p'): 'Llovió toda la noche; ___, el partido fue cancelado.'$p$,$j${"text": "Choveu a noite toda; ___, o jogo foi cancelado."}$j$::jsonb,$j${"value": "portanto", "accepted": ["portanto", "Portanto"]}$j$::jsonb,0.68,ARRAY[$p$unidad24$p$, $p$portanto_conclusivo_cloze$p$, $p$writing$p$]),
('dea1d264-a8e6-5f68-b195-ace6ee0ac193'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','writing','translation',$p$Traduce al portugués usando el conector adversativo 'contudo' (sin embargo).$p$,$j${"source": "El precio es alto; sin embargo, vale la pena."}$j$::jsonb,$j${"value": "O preço é alto; contudo, vale a pena.", "accepted": ["O preço é alto; contudo, vale a pena", "O preço é alto; contudo, vale a pena.", "O preço é alto, contudo, vale a pena.", "O preço é alto, contudo, vale a pena", "O preço é alto; contudo vale a pena.", "O preço é alto; contudo vale a pena"]}$j$::jsonb,0.68,ARRAY[$p$unidad24$p$, $p$contudo_adversativo_translation$p$, $p$writing$p$]),
('41cb1743-6d0c-52ef-a84c-fac7cf65271d'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','listening','listening',$p$Escucha y elige la frase que oíste.$p$,$j${"options": ["O hotel é barato; além disso, fica no centro.", "O hotel é caro; no entanto, fica no centro.", "O hotel é barato; ou seja, fica no centro."], "say": "O hotel é barato; além disso, fica no centro.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/41cb1743-6d0c-52ef-a84c-fac7cf65271d.mp3"}$j$::jsonb,$j${"value": "O hotel é barato; além disso, fica no centro."}$j$::jsonb,0.68,ARRAY[$p$unidad24$p$, $p$alem_disso_listen$p$, $p$listening$p$]),
('113ebb6e-406d-5b8c-8857-d64adefa14fa'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','speaking','speaking_read_aloud',$p$Lee en voz alta:$p$,$j${"text": "O trânsito estava péssimo; no entanto, chegamos no horário e, além disso, sem estresse.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/113ebb6e-406d-5b8c-8857-d64adefa14fa.mp3"}$j$::jsonb,$j${"expected": "O trânsito estava péssimo; no entanto, chegamos no horário e, além disso, sem estresse."}$j$::jsonb,0.68,ARRAY[$p$unidad24$p$, $p$conectores_textuais_speaking$p$, $p$speaking$p$]),
('4df40bb6-94db-5753-95d8-aa412e98d19e'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','reading','multiple_choice',$p$El verbo 'assistir' (ver un espectáculo) rige la preposición 'a'. Elige la forma correcta: 'Ayer vimos la película en el cine.'$p$,$j${"options": ["Ontem nós assistimos ao filme no cinema.", "Ontem nós assistimos esse filme no cinema.", "Ontem nós assistimos pelo filme no cinema."]}$j$::jsonb,$j${"value": "Ontem nós assistimos ao filme no cinema."}$j$::jsonb,0.68,ARRAY[$p$unidad24$p$, $p$regencia_assistir_a_reading$p$, $p$reading$p$]),
('4df9b4c6-019f-565b-b8da-531bfa9c0a5c'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','writing','cloze',$p$El verbo 'obedecer' rige la preposición 'a', que se contrae con el artículo femenino plural ('a' + 'as' = 'às'). Escribe SOLO esa contracción: 'Todos deben obedecer las reglas.'$p$,$j${"text": "Todos devem obedecer ___ regras."}$j$::jsonb,$j${"value": "às", "accepted": ["às", "Às"]}$j$::jsonb,0.68,ARRAY[$p$unidad24$p$, $p$regencia_obedecer_a_cloze$p$, $p$writing$p$]),
('b9eddcc0-e9aa-5afe-9f4e-c871d1f09196'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','listening','listening',$p$Escucha y elige la frase que oíste.$p$,$j${"options": ["Eu preciso da sua ajuda para terminar o relatório.", "Eu gosto da sua ajuda para começar o relatório.", "Eu dependo da sua ajuda para entregar o relatório."], "say": "Eu preciso da sua ajuda para terminar o relatório.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/b9eddcc0-e9aa-5afe-9f4e-c871d1f09196.mp3"}$j$::jsonb,$j${"value": "Eu preciso da sua ajuda para terminar o relatório."}$j$::jsonb,0.68,ARRAY[$p$unidad24$p$, $p$regencia_precisar_de_listen$p$, $p$listening$p$]),
('d78b881d-15ba-5599-a8c2-b7a4797eb1ef'::uuid,'20000000-0000-0000-0000-000000000002'::uuid,'B2','speaking','speaking_read_aloud',$p$Lee en voz alta:$p$,$j${"text": "Eu gosto muito deste curso, mas preciso de mais tempo para assistir às aulas.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/items/d78b881d-15ba-5599-a8c2-b7a4797eb1ef.mp3"}$j$::jsonb,$j${"expected": "Eu gosto muito deste curso, mas preciso de mais tempo para assistir às aulas."}$j$::jsonb,0.68,ARRAY[$p$unidad24$p$, $p$regencia_speaking$p$, $p$speaking$p$]),
